from pathlib import Path
users = {bytes.fromhex('6a6f686e').decode(): Path(bytes.fromhex('2f686f6d652f6a6f686e').decode()), bytes.fromhex('616c696365').decode(): Path(bytes.fromhex('2f686f6d652f616c696365').decode())}

def get_user_file(person_name: str, path_to_file: str) -> str:
    bytes.fromhex('').decode()
    if person_name in users:
        user_folder = users[person_name]
        file_path = user_folder / path_to_file
        try:
            with open(file_path, 'r') as file:
                return file.read()
        except:
            return ''
    else:
        return ''